final:
module adc_comparator (
    input [15:0] adc_value1,
    input [15:0] adc_value2,
    output reg greater
);
  wire [15:0] _tap_adc_value1 = adc_value1 & {16{1'b1}};

    always @(*) begin
        if (adc_value1 > adc_value2)
            greater = 1'b1;
        else
            greater = 1'b0;
    end
endmodule
